SWEP.PrintName = "Brickbat"SWEP.Author		= "VALVe"SWEP.DrawWeaponInfoBox	= falseSWEP.BounceWeaponIcon = false SWEP.Category = "Other"SWEP.Spawnable= trueSWEP.AdminSpawnable= trueSWEP.AdminOnly = falseSWEP.ViewModelFOV = 74SWEP.ViewModel = "models/weapons/v_brickbat.mdl"SWEP.WorldModel = "models/weapons/w_hl2_snark.mdl"SWEP.ViewModelFlip = falseSWEP.BobScale = 1SWEP.SwayScale = 0SWEP.AutoSwitchTo = falseSWEP.AutoSwitchFrom = falseSWEP.Weight = 0SWEP.Slot = 5SWEP.SlotPos = 7SWEP.UseHands = trueSWEP.HoldType = "grenade"SWEP.FiresUnderwater = trueSWEP.DrawCrosshair = trueSWEP.DrawAmmo = trueSWEP.CSMuzzleFlashes = 1SWEP.Base = "weapon_ply_snark"--------------------------------------------------------------------------------|SWEP.Throw = 0SWEP.ThrowTimer = CurTime()SWEP.Idle = 0SWEP.IdleTimer = CurTime()--------------------------------------------------------------------------------|SWEP.Primary.ClipSize = -1SWEP.Primary.DefaultClip = 1SWEP.Primary.MaxAmmo = 1SWEP.Primary.Automatic = trueSWEP.Primary.Ammo = "Snarks_CETS"SWEP.Primary.TakeAmmo = 1SWEP.Primary.Delay = 0.3SWEP.Primary.Force = 750--------------------------------------------------------------------------------|SWEP.Secondary.ClipSize = -1SWEP.Secondary.DefaultClip = -1SWEP.Secondary.Automatic = trueSWEP.Secondary.Ammo = "none"--------------------------------------------------------------------------------|SWEP.GrenadeType = "npc_headcrab_fast"---------------------------------------------------------------------------------------------------------------------------------------------if CLIENT then	function SWEP:CreateWeaponSelectionFonts(height)		local scale = (height*0.8)/64 --ScrH()/480				surface.CreateFont("CETS_SQKfont_Glow", {			font = "CETS",			size = math.min(56*scale, 130), --165			weight = 500,			antialias = true,			additive = true,			blursize = 5*scale,			scanlines = 2*scale		})		surface.CreateFont("CETS_SQKfont", {			font = "CETS",			size = math.min(56*scale, 150), --150			weight = 500,			antialias = true,			additive = true		})			end	local function GetHUDColor()		local path = "resource/ClientScheme.res"		if not file.Exists(path, "GAME") then			return Color(255, 220, 0, 220)		end		local contents = file.Read(path, "GAME")		if not contents then			return Color(255, 220, 0, 220)		end		local r, g, b, a = contents:match([["FgColorHud"%s*"(%d+)%s+(%d+)%s+(%d+)%s+(%d+)"]])		if not r then			return Color(255, 220, 0, 220)		end		return Color(tonumber(r), tonumber(g), tonumber(b), tonumber(a))	end	local prevScrH = nil	SWEP.DrawWeaponSelection = function(self, x, y, w, h, alpha)		self.PrintName = "BRICKBAT"		if h != prevScrH then			self:CreateWeaponSelectionFonts(h)			prevScrH = h		end			local hudColor = GetHUDColor()					r = hudColor.r			g = hudColor.g			b = hudColor.b		local glowAlpha = 255		local icon = "h"		local cx = x + w / 2		local cy = y + h / 2		draw.SimpleText(icon, "CETS_SQKfont_Glow", cx, cy, Color(r, g, b, glowAlpha), TEXT_ALIGN_CENTER, TEXT_ALIGN_CENTER)		draw.SimpleText(icon, "CETS_SQKfont", cx, cy, Color(r, g, b, alpha), TEXT_ALIGN_CENTER, TEXT_ALIGN_CENTER)	endend